using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests;

public class PaginatedListTests
{
    [Fact]
    public void Create_FirstPage_HasCorrectProperties()
    {
        var source = Enumerable.Range(1, 25).AsQueryable();
        var list = PaginatedList<int>.Create(source, 1, 10);

        Assert.Equal(1, list.PageIndex);
        Assert.Equal(3, list.TotalPages);
        Assert.Equal(10, list.Count);
        Assert.False(list.HasPreviousPage);
        Assert.True(list.HasNextPage);
    }

    [Fact]
    public void Create_MiddlePage_HasBothNavigationOptions()
    {
        var source = Enumerable.Range(1, 25).AsQueryable();
        var list = PaginatedList<int>.Create(source, 2, 10);

        Assert.Equal(2, list.PageIndex);
        Assert.True(list.HasPreviousPage);
        Assert.True(list.HasNextPage);
        Assert.Equal(10, list.Count);
    }

    [Fact]
    public void Create_LastPage_HasNoPreviousButNoNext()
    {
        var source = Enumerable.Range(1, 25).AsQueryable();
        var list = PaginatedList<int>.Create(source, 3, 10);

        Assert.Equal(3, list.PageIndex);
        Assert.True(list.HasPreviousPage);
        Assert.False(list.HasNextPage);
        Assert.Equal(5, list.Count);
    }

    [Fact]
    public void Create_EmptySource_ReturnsEmptyList()
    {
        var source = Enumerable.Empty<int>().AsQueryable();
        var list = PaginatedList<int>.Create(source, 1, 10);

        Assert.Empty(list);
        Assert.Equal(0, list.TotalPages);
        Assert.False(list.HasPreviousPage);
        Assert.False(list.HasNextPage);
    }

    [Fact]
    public void Create_SinglePage_NoNavigation()
    {
        var source = Enumerable.Range(1, 5).AsQueryable();
        var list = PaginatedList<int>.Create(source, 1, 10);

        Assert.Equal(5, list.Count);
        Assert.Equal(1, list.TotalPages);
        Assert.False(list.HasPreviousPage);
        Assert.False(list.HasNextPage);
    }

    [Fact]
    public void Create_ExactPageBoundary_CorrectTotalPages()
    {
        var source = Enumerable.Range(1, 20).AsQueryable();
        var list = PaginatedList<int>.Create(source, 1, 10);

        Assert.Equal(2, list.TotalPages);
        Assert.Equal(10, list.Count);
    }

    [Fact]
    public void Create_PageSize1_ManyPages()
    {
        var source = Enumerable.Range(1, 5).AsQueryable();
        var list = PaginatedList<int>.Create(source, 3, 1);

        Assert.Equal(3, list.PageIndex);
        Assert.Equal(5, list.TotalPages);
        Assert.Single(list);
        Assert.Equal(3, list[0]);
        Assert.True(list.HasPreviousPage);
        Assert.True(list.HasNextPage);
    }

    [Fact]
    public void TotalPages_Calculation_RoundsUp()
    {
        // 11 items with page size 5 => 3 pages
        var source = Enumerable.Range(1, 11).AsQueryable();
        var list = PaginatedList<int>.Create(source, 1, 5);
        Assert.Equal(3, list.TotalPages);
    }

    [Fact]
    public void Create_ContainsCorrectItems()
    {
        var source = Enumerable.Range(1, 30).AsQueryable();
        var list = PaginatedList<int>.Create(source, 2, 10);

        Assert.Equal(11, list[0]);
        Assert.Equal(20, list[9]);
    }
}

