using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Xunit;

namespace ContosoUniversity.Tests.Services;

public class NotificationServiceTests : IDisposable
{
    private readonly NotificationService _service;

    public NotificationServiceTests()
    {
        _service = new NotificationService();
        // Drain the static queue to avoid cross-test interference
        while (_service.ReceiveNotification() != null) { }
    }

    public void Dispose()
    {
        while (_service.ReceiveNotification() != null) { }
        _service.Dispose();
    }

    [Fact]
    public void SendNotification_CreatesNotificationWithCorrectMessage_Create()
    {
        _service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE);
        var notification = _service.ReceiveNotification();

        Assert.NotNull(notification);
        Assert.Equal("Student", notification.EntityType);
        Assert.Equal("1", notification.EntityId);
        Assert.Equal("CREATE", notification.Operation);
        Assert.Equal("New Student 'John Doe' has been created", notification.Message);
        Assert.Equal("System", notification.CreatedBy);
        Assert.False(notification.IsRead);
    }

    [Fact]
    public void SendNotification_WithDisplayName_IncludesDisplayNameInMessage()
    {
        _service.SendNotification("Course", "42", "Chemistry 101", EntityOperation.UPDATE);
        var notification = _service.ReceiveNotification();

        Assert.NotNull(notification);
        Assert.Equal("Course 'Chemistry 101' has been updated", notification.Message);
    }

    [Fact]
    public void SendNotification_WithoutDisplayName_UsesIdFormat()
    {
        _service.SendNotification("Student", "5", EntityOperation.DELETE);
        var notification = _service.ReceiveNotification();

        Assert.NotNull(notification);
        Assert.Equal("Student (ID: 5) has been deleted", notification.Message);
    }

    [Fact]
    public void SendNotification_WithUserName_SetsCreatedBy()
    {
        _service.SendNotification("Student", "1", "Test", EntityOperation.CREATE, "admin");
        var notification = _service.ReceiveNotification();

        Assert.NotNull(notification);
        Assert.Equal("admin", notification.CreatedBy);
    }

    [Fact]
    public void SendNotification_WithNullUserName_SetsSystemAsCreatedBy()
    {
        _service.SendNotification("Student", "1", "Test", EntityOperation.CREATE, null);
        var notification = _service.ReceiveNotification();

        Assert.Equal("System", notification!.CreatedBy);
    }

    [Fact]
    public void ReceiveNotification_WhenQueueEmpty_ReturnsNull()
    {
        var result = _service.ReceiveNotification();
        Assert.Null(result);
    }

    [Fact]
    public void ReceiveNotification_DequeuesInOrder()
    {
        _service.SendNotification("A", "1", "First", EntityOperation.CREATE);
        _service.SendNotification("B", "2", "Second", EntityOperation.UPDATE);
        _service.SendNotification("C", "3", "Third", EntityOperation.DELETE);

        var first = _service.ReceiveNotification();
        var second = _service.ReceiveNotification();
        var third = _service.ReceiveNotification();

        Assert.Equal("A", first!.EntityType);
        Assert.Equal("B", second!.EntityType);
        Assert.Equal("C", third!.EntityType);
    }

    [Fact]
    public void MultipleSendAndReceive_WorksCorrectly()
    {
        _service.SendNotification("X", "1", EntityOperation.CREATE);
        var n1 = _service.ReceiveNotification();
        Assert.NotNull(n1);

        _service.SendNotification("Y", "2", EntityOperation.UPDATE);
        _service.SendNotification("Z", "3", EntityOperation.DELETE);

        var n2 = _service.ReceiveNotification();
        var n3 = _service.ReceiveNotification();
        var n4 = _service.ReceiveNotification();

        Assert.Equal("Y", n2!.EntityType);
        Assert.Equal("Z", n3!.EntityType);
        Assert.Null(n4);
    }

    [Fact]
    public void GenerateMessage_Create_ProducesCorrectMessage()
    {
        _service.SendNotification("Student", "1", "Jane Doe", EntityOperation.CREATE);
        var n = _service.ReceiveNotification();
        Assert.Equal("New Student 'Jane Doe' has been created", n!.Message);
    }

    [Fact]
    public void GenerateMessage_Update_ProducesCorrectMessage()
    {
        _service.SendNotification("Department", "5", "Math", EntityOperation.UPDATE);
        var n = _service.ReceiveNotification();
        Assert.Equal("Department 'Math' has been updated", n!.Message);
    }

    [Fact]
    public void GenerateMessage_Delete_ProducesCorrectMessage()
    {
        _service.SendNotification("Course", "10", "Physics", EntityOperation.DELETE);
        var n = _service.ReceiveNotification();
        Assert.Equal("Course 'Physics' has been deleted", n!.Message);
    }

    [Fact]
    public void GenerateMessage_WithoutDisplayName_UsesIdFormat()
    {
        _service.SendNotification("Student", "42", EntityOperation.CREATE);
        var n = _service.ReceiveNotification();
        Assert.Equal("New Student (ID: 42) has been created", n!.Message);
    }

    [Fact]
    public void Dispose_DoesNotThrow()
    {
        var service = new NotificationService();
        var ex = Record.Exception(() => service.Dispose());
        Assert.Null(ex);
    }

    [Fact]
    public void MarkAsRead_DoesNotThrow()
    {
        var ex = Record.Exception(() => _service.MarkAsRead(1));
        Assert.Null(ex);
    }

    [Fact]
    public void SendNotification_SetsCreatedAtToRecentTime()
    {
        var before = DateTime.Now.AddSeconds(-1);
        _service.SendNotification("Student", "1", EntityOperation.CREATE);
        var after = DateTime.Now.AddSeconds(1);

        var n = _service.ReceiveNotification();
        Assert.InRange(n!.CreatedAt, before, after);
    }

    [Fact]
    public void SendNotification_SetsIsReadFalse()
    {
        _service.SendNotification("Student", "1", EntityOperation.CREATE);
        var n = _service.ReceiveNotification();
        Assert.False(n!.IsRead);
    }
}

