using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using System;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers;

public class StudentsControllerTests : IDisposable
{
    private readonly SchoolContext _context;
    private readonly StudentsController _controller;

    public StudentsControllerTests()
    {
        _context = TestHelpers.CreateSeededContext();
        _controller = new StudentsController(_context);
        _controller.ControllerContext = new ControllerContext
        {
            HttpContext = new DefaultHttpContext()
        };
    }

    public void Dispose()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    #region Index

    [Fact]
    public void Index_DefaultSort_ReturnsSortedByLastNameAsc()
    {
        var result = _controller.Index(null, null, null, null) as ViewResult;
        Assert.NotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.NotNull(model);
        Assert.True(model.Count > 0);
        // Default sort is by LastName ascending
        var names = model.Select(s => s.LastName).ToList();
        Assert.Equal(names.OrderBy(n => n), names);
    }

    [Fact]
    public void Index_NameDescSort_ReturnsSortedByLastNameDesc()
    {
        var result = _controller.Index("name_desc", null, null, null) as ViewResult;
        Assert.NotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.NotNull(model);
        var names = model.Select(s => s.LastName).ToList();
        Assert.Equal(names.OrderByDescending(n => n), names);
    }

    [Fact]
    public void Index_DateSort_ReturnsSortedByDateAsc()
    {
        var result = _controller.Index("Date", null, null, null) as ViewResult;
        Assert.NotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.NotNull(model);
        var dates = model.Select(s => s.EnrollmentDate).ToList();
        Assert.Equal(dates.OrderBy(d => d), dates);
    }

    [Fact]
    public void Index_DateDescSort_ReturnsSortedByDateDesc()
    {
        var result = _controller.Index("date_desc", null, null, null) as ViewResult;
        Assert.NotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.NotNull(model);
        var dates = model.Select(s => s.EnrollmentDate).ToList();
        Assert.Equal(dates.OrderByDescending(d => d), dates);
    }

    [Fact]
    public void Index_SearchFiltering_FiltersStudentsByName()
    {
        var result = _controller.Index(null, null, "Alexander", null) as ViewResult;
        Assert.NotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.NotNull(model);
        Assert.Single(model);
        Assert.Equal("Alexander", model[0].LastName);
    }

    [Fact]
    public void Index_SearchFiltering_FiltersByFirstName()
    {
        var result = _controller.Index(null, null, "Carson", null) as ViewResult;
        Assert.NotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.NotNull(model);
        Assert.Contains(model, s => s.FirstMidName == "Carson");
    }

    [Fact]
    public void Index_Pagination_ReturnsCorrectPage()
    {
        // Add more students for pagination testing
        for (int i = 0; i < 15; i++)
        {
            _context.Students.Add(new Student
            {
                FirstMidName = $"Student{i}",
                LastName = $"Test{i:D3}",
                EnrollmentDate = DateTime.Today
            });
        }
        _context.SaveChanges();

        var result = _controller.Index(null, null, null, 2) as ViewResult;
        Assert.NotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.NotNull(model);
        Assert.Equal(2, model.PageIndex);
    }

    [Fact]
    public void Index_SearchStringResetsPage()
    {
        // When searchString is not null, page should be reset to 1
        var result = _controller.Index(null, null, "A", null) as ViewResult;
        Assert.NotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.NotNull(model);
        Assert.Equal(1, model.PageIndex);
    }

    [Fact]
    public void Index_CurrentFilterUsedWhenSearchStringNull()
    {
        var result = _controller.Index(null, "Alexander", null, null) as ViewResult;
        Assert.NotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.NotNull(model);
        Assert.Single(model);
    }

    [Fact]
    public void Index_SetsViewBagProperties()
    {
        var result = _controller.Index("Date", null, "test", null) as ViewResult;
        Assert.NotNull(result);
        Assert.Equal("Date", _controller.ViewBag.CurrentSort);
        Assert.Equal("date_desc", _controller.ViewBag.DateSortParm);
        Assert.Equal("test", _controller.ViewBag.CurrentFilter);
    }

    #endregion

    #region Details

    [Fact]
    public void Details_ValidId_ReturnsViewWithStudent()
    {
        var student = _context.Students.First();
        var result = _controller.Details(student.ID) as ViewResult;
        Assert.NotNull(result);
        var model = result.Model as Student;
        Assert.NotNull(model);
        Assert.Equal(student.ID, model.ID);
    }

    [Fact]
    public void Details_NullId_ReturnsBadRequest()
    {
        var result = _controller.Details(null);
        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    #endregion

    #region Create GET

    [Fact]
    public void Create_Get_ReturnsViewWithDefaultDate()
    {
        var result = _controller.Create() as ViewResult;
        Assert.NotNull(result);
        var model = result.Model as Student;
        Assert.NotNull(model);
        Assert.Equal(DateTime.Today, model.EnrollmentDate);
    }

    #endregion

    #region Create POST

    [Fact]
    public void Create_Post_ValidStudent_SavesAndRedirects()
    {
        var student = new Student
        {
            FirstMidName = "Test",
            LastName = "User",
            EnrollmentDate = new DateTime(2020, 9, 1)
        };

        var result = _controller.Create(student) as RedirectToActionResult;
        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);

        var saved = _context.Students.FirstOrDefault(s => s.LastName == "User");
        Assert.NotNull(saved);
        Assert.Equal("Test", saved.FirstMidName);
    }

    [Fact]
    public void Create_Post_InvalidModel_ReturnsView()
    {
        _controller.ModelState.AddModelError("LastName", "Required");
        var student = new Student
        {
            FirstMidName = "Test",
            EnrollmentDate = new DateTime(2020, 9, 1)
        };

        var result = _controller.Create(student) as ViewResult;
        Assert.NotNull(result);
    }

    [Fact]
    public void Create_Post_MinValueDate_AddsModelError()
    {
        var student = new Student
        {
            FirstMidName = "Test",
            LastName = "User",
            EnrollmentDate = DateTime.MinValue
        };

        var result = _controller.Create(student) as ViewResult;
        Assert.NotNull(result);
        Assert.False(_controller.ModelState.IsValid);
    }

    [Fact]
    public void Create_Post_OutOfRangeDate_AddsModelError()
    {
        var student = new Student
        {
            FirstMidName = "Test",
            LastName = "User",
            EnrollmentDate = new DateTime(1000, 1, 1)
        };

        var result = _controller.Create(student) as ViewResult;
        Assert.NotNull(result);
        Assert.True(_controller.ModelState.ContainsKey("EnrollmentDate"));
    }

    #endregion

    #region Edit GET

    [Fact]
    public void Edit_Get_ValidId_ReturnsViewWithStudent()
    {
        var student = _context.Students.First();
        var result = _controller.Edit(student.ID) as ViewResult;
        Assert.NotNull(result);
        var model = result.Model as Student;
        Assert.NotNull(model);
        Assert.Equal(student.ID, model.ID);
    }

    [Fact]
    public void Edit_Get_NullId_ReturnsBadRequest()
    {
        var result = _controller.Edit(null);
        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Edit_Get_NotFound_ReturnsNotFound()
    {
        var result = _controller.Edit(99999);
        Assert.IsType<NotFoundResult>(result);
    }

    #endregion

    #region Edit POST

    [Fact]
    public void Edit_Post_ValidSave_Redirects()
    {
        var student = _context.Students.First();
        // Detach to avoid tracking conflict
        _context.Entry(student).State = EntityState.Detached;

        var updatedStudent = new Student
        {
            ID = student.ID,
            FirstMidName = "Updated",
            LastName = "Name",
            EnrollmentDate = new DateTime(2020, 1, 1)
        };

        var result = _controller.Edit(updatedStudent) as RedirectToActionResult;
        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
    }

    [Fact]
    public void Edit_Post_InvalidModel_ReturnsView()
    {
        _controller.ModelState.AddModelError("LastName", "Required");
        var student = new Student
        {
            ID = 1,
            FirstMidName = "Test",
            EnrollmentDate = new DateTime(2020, 1, 1)
        };

        var result = _controller.Edit(student) as ViewResult;
        Assert.NotNull(result);
    }

    [Fact]
    public void Edit_Post_DateValidation_MinValue()
    {
        var student = _context.Students.First();
        _context.Entry(student).State = EntityState.Detached;

        var updated = new Student
        {
            ID = student.ID,
            FirstMidName = "Test",
            LastName = "User",
            EnrollmentDate = DateTime.MinValue
        };

        var result = _controller.Edit(updated) as ViewResult;
        Assert.NotNull(result);
        Assert.False(_controller.ModelState.IsValid);
    }

    #endregion

    #region Delete GET

    [Fact]
    public void Delete_Get_ValidId_ReturnsViewWithStudent()
    {
        var student = _context.Students.First();
        var result = _controller.Delete(student.ID) as ViewResult;
        Assert.NotNull(result);
        var model = result.Model as Student;
        Assert.NotNull(model);
        Assert.Equal(student.ID, model.ID);
    }

    [Fact]
    public void Delete_Get_NullId_ReturnsBadRequest()
    {
        var result = _controller.Delete(null);
        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Delete_Get_NotFound_ReturnsNotFound()
    {
        var result = _controller.Delete(99999);
        Assert.IsType<NotFoundResult>(result);
    }

    #endregion

    #region DeleteConfirmed

    [Fact]
    public void DeleteConfirmed_RemovesStudentAndRedirects()
    {
        var student = _context.Students.First();
        var id = student.ID;

        var result = _controller.DeleteConfirmed(id) as RedirectToActionResult;
        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
        Assert.Null(_context.Students.Find(id));
    }

    #endregion
}

using ContosoUniversity.Controllers;
