+using ContosoUniversity.Controllers;
+using ContosoUniversity.Data;
+using ContosoUniversity.Models;
+using ContosoUniversity.Services;
+using Microsoft.AspNetCore.Http;
+using Microsoft.AspNetCore.Mvc;
+using System;
+using System.Linq;
+using Xunit;
+
+namespace ContosoUniversity.Tests.Controllers;
+
+public class NotificationsControllerTests : IDisposable
+{
+    private readonly SchoolContext _context;
+    private readonly NotificationsController _controller;
+    private readonly NotificationService _drainService;
+
+    public NotificationsControllerTests()
+    {
+        _context = TestHelpers.CreateContext();
+        _controller = new NotificationsController(_context);
+        _controller.ControllerContext = new ControllerContext
+        {
+            HttpContext = new DefaultHttpContext()
+        };
+        // Drain the static queue
+        _drainService = new NotificationService();
+        while (_drainService.ReceiveNotification() != null) { }
+    }
+
+    public void Dispose()
+    {
+        while (_drainService.ReceiveNotification() != null) { }
+        _drainService.Dispose();
+        _controller.Dispose();
+        _context.Dispose();
+    }
+
+    [Fact]
+    public void GetNotifications_EmptyQueue_ReturnsEmptyList()
+    {
+        var result = _controller.GetNotifications();
+        Assert.NotNull(result);
+        var json = result.Value;
+        Assert.NotNull(json);
+
+        // Use reflection to check the anonymous type properties
+        var successProp = json.GetType().GetProperty("success");
+        Assert.True((bool)successProp!.GetValue(json)!);
+
+        var countProp = json.GetType().GetProperty("count");
+        Assert.Equal(0, (int)countProp!.GetValue(json)!);
+    }
+
+    [Fact]
+    public void GetNotifications_WithNotifications_ReturnsNotifications()
+    {
+        var service = new NotificationService();
+        service.SendNotification("Student", "1", "Test", EntityOperation.CREATE);
+        service.SendNotification("Course", "2", "Math", EntityOperation.UPDATE);
+
+        var result = _controller.GetNotifications();
+        var json = result.Value!;
+
+        var countProp = json.GetType().GetProperty("count");
+        var count = (int)countProp!.GetValue(json)!;
+        Assert.True(count > 0);
+    }
+
+    [Fact]
+    public void GetNotifications_LimitsToMax10()
+    {
+        var service = new NotificationService();
+        for (int i = 0; i < 15; i++)
+        {
+            service.SendNotification("Entity", i.ToString(), EntityOperation.CREATE);
+        }
+
+        var result = _controller.GetNotifications();
+        var json = result.Value!;
+
+        var countProp = json.GetType().GetProperty("count");
+        var count = (int)countProp!.GetValue(json)!;
+        Assert.True(count <= 10);
+    }
+
+    [Fact]
+    public void MarkAsRead_ReturnsSuccess()
+    {
+        var result = _controller.MarkAsRead(1);
+        Assert.NotNull(result);
+        var json = result.Value!;
+
+        var successProp = json.GetType().GetProperty("success");
+        Assert.True((bool)successProp!.GetValue(json)!);
+    }
+
+    [Fact]
+    public void Index_ReturnsView()
+    {
+        var result = _controller.Index() as ViewResult;
+        Assert.NotNull(result);
+    }
+}
